linkList.script:
var page = this;
var kids = this.KMComponentsMng.$Children || {};
function byName(name){ return Object.values(kids).find(function(v){ return v && (v.UIName===name || v.name===name || (v.propData && v.propData.UIName===name)); }); }
function propOf(obj){ return obj && (obj._props && obj._props.propData || obj.propData || obj); }
function getVar(name){
  if (page.$Variable && typeof page.$Variable[name] !== 'undefined') return page.$Variable[name];
  if (page.variableMng && page.variableMng.getVarByName) { var mv = page.variableMng.getVarByName(name); if (mv) { if (typeof mv.getValue === 'function') return mv.getValue(); return mv.varValue; } }
}
function setVar(name, value){
  page.$Variable = page.$Variable || {};
  page.$Variable[name] = value;
  if (page.variableMng && page.variableMng.getVarByName && typeof page.setVariable === 'function') { var mv = page.variableMng.getVarByName(name); if (mv) page.setVariable(mv, value); }
}
function loadRows(){
  var raw = getVar('seedData') || '[]';
  try { return JSON.parse(raw); } catch(e) { return []; }
}
function buildRows(){
  var kw = String(getVar('filterKey') || '').trim().toUpperCase();
  var all = loadRows();
  if (!kw) return all;
  return all.filter(function(r){
    return String(r.station||'').toUpperCase().indexOf(kw) >= 0 || String(r.area||'').toUpperCase().indexOf(kw) >= 0 || String(r.status||'').toUpperCase().indexOf(kw) >= 0;
  });
}
function buildColumns(){
  return [
    {prop:'station',label:'\u7ad9\u70b9',minWidth:'140',align:'left',type:'',columnKey:'',fixed:false},
    {prop:'area',label:'\u533a\u57df',minWidth:'84',align:'center',type:'',columnKey:'',fixed:false},
    {prop:'status',label:'\u72b6\u6001',minWidth:'100',align:'center',type:'',columnKey:'',fixed:false},
    {prop:'flow',label:'\u6d41\u91cf',minWidth:'100',align:'right',type:'',columnKey:'',fixed:false},
    {prop:'pressure',label:'\u538b\u529b',minWidth:'100',align:'right',type:'',columnKey:'',fixed:false}
  ];
}
function buildOption(rows, counter){
  return {
    color:['#2563eb'],
    tooltip:{trigger:'axis'},
    grid:{left:44,right:24,top:36,bottom:36},
    xAxis:{type:'category',boundaryGap:false,data:rows.map(function(r){ return r.station; }),axisLine:{lineStyle:{color:'#94a3b8'}},axisLabel:{color:'#475569'}},
    yAxis:{type:'value',axisLine:{show:false},splitLine:{lineStyle:{color:'#e2e8f0'}},axisLabel:{color:'#475569'}},
    series:[{name:'\u6d41\u91cf\u8d8b\u52bf',type:'line',smooth:true,symbol:'circle',symbolSize:7,lineStyle:{width:3},areaStyle:{opacity:0.12},data:rows.map(function(r){ return Number(r.trend || 0) + Number(counter || 0); })}]
  };
}
page.__pilotRefresh = function(reason){
  var input = byName('demo_filter_input');
  var button = byName('demo_query_button');
  var table = byName('demo_table');
  var chart = byName('demo_chart');
  var tree = byName('demo_area_tree');
  var counter = Number(getVar('refreshCounter') || 0);
  var rows = buildRows();
  var columns = buildColumns();
  var cfg = { border:true, fit:true, showHeader:true, emptyText:'\u6682\u65e0\u5339\u914d\u6570\u636e', pagination:true, pageSize:10, columns:columns, totalData:rows };
  if (table && typeof table.table === 'function') table.table(cfg);
  if (propOf(table)) propOf(table).detailConfig = 'this.table(' + JSON.stringify(cfg) + ')';
  var option = buildOption(rows, counter);
  if (chart && typeof chart.SetOption === 'function') chart.SetOption(option, true);
  if (propOf(chart)) propOf(chart).detailConfig = 'option=' + JSON.stringify(option);
  if (button && typeof button.button === 'function') button.button({ text: '\u67e5\u8be2' + (String(getVar('filterKey') || '').trim() ? '\uff1a' + String(getVar('filterKey')).trim() : '\u5168\u90e8') + '(' + rows.length + ')' });
  if (tree && propOf(tree)) { propOf(tree).data = [{ label:'\u5168\u90e8\u533a\u57df', children:[{label:'A\u533a'},{label:'B\u533a'}] }]; }
  page.__pilotLast = { reason: reason, counter: counter, rows: rows.length, filterKey: getVar('filterKey') || '' };
  return page.__pilotLast;
};

var input = byName('demo_filter_input');

var kw = '';

if (input) { kw = String((input.getProperty && input.getProperty('value')) || (input.propData && input.propData.value) || '').trim(); }

setVar('filterKey', kw);

var current = Number(getVar('refreshCounter') || 0);

setVar('refreshCounter', current + 1);

page.__pilotRefresh('button');
